"""
LRU eviction helper for cache module.
"""

import threading
from collections import OrderedDict
from typing import Any, Optional, Tuple


class LRUStore:
    """Thread-safe LRU key-value store with capacity limit."""

    def __init__(self, capacity: int):
        self.capacity = capacity
        self._store: OrderedDict = OrderedDict()
        self._lock = threading.Lock()

    def get(self, key: str) -> Optional[Any]:
        with self._lock:
            if key in self._store:
                self._store.move_to_end(key)
                return self._store[key]
            return None

    def put(self, key: str, value: Any) -> Optional[Tuple[str, Any]]:
        """Insert key-value. Returns evicted (key, value) if capacity exceeded, else None."""
        with self._lock:
            if key in self._store:
                self._store.move_to_end(key)
                self._store[key] = value
                return None
            if len(self._store) >= self.capacity:
                evicted = self._store.popitem(last=False)
                self._store[key] = value
                return evicted
            self._store[key] = value
            return None

    def remove(self, key: str) -> Optional[Any]:
        with self._lock:
            if key in self._store:
                return self._store.pop(key)
            return None

    def clear(self):
        with self._lock:
            self._store.clear()

    def __len__(self):
        with self._lock:
            return len(self._store)

    def keys(self):
        with self._lock:
            return list(self._store.keys())
